mapper.select:
SELECT X.* , ROW_NUMBER() OVER(ORDER BY text) AS pageindex FROM ( SELECT DOC_USER.USER_NM AS text , DOC_USER.USER_CD AS id FROM DOCS_USER DOC_USER WHERE DOC_USER.USER_CD = ( SELECT TEAM_LEADER_USER_CD FROM DOCS_DEPT WHERE DEPT_CD = #{sessionUser.deptCd} )
AND DOC_USER.USER_NM LIKE '%' || #{term} || '%'
) X

SELECT X.* , ROW_NUMBER() OVER(ORDER BY text) AS pageindex FROM ( SELECT DOC_USER.USER_NM AS text , DOC_USER.USER_CD AS id FROM DOCS_USER DOC_USER WHERE DOC_USER.USER_CD IN ( SELECT TEAM_LEADER_USER_CD FROM DOCS_DEPT WHERE TEAM_LEADER_USER_CD IS NOT NULL )
AND DOC_USER.USER_NM LIKE '%' || #{term} || '%'
) X

SELECT X.* FROM ( SELECT USER_CD AS id , USER_NM || '[' || USER_ID || ']' AS text , USER_NM || '[' || USER_ID || ']' AS title , ROW_NUMBER() OVER(ORDER BY USER_NM) AS pageindex FROM DOCS_USER WHERE 1=1
AND USER_NM LIKE '%' || #{term} || '%'
) X
WHERE PAGEINDEX BETWEEN #{posStart} AND #{count} * #{page}

SELECT X.* FROM ( SELECT COMPANY_USER.USER_NM AS text , COMPANY_USER.USER_CD AS id , ROW_NUMBER() OVER(ORDER BY DISTRIBUTION_PERSON_YN DESC, USER_NM) AS pageindex FROM DOCS_USER COMPANY_USER WHERE 1=1
AND COMPANY_USER.COMPANY_CD = #{companyCd}
AND COMPANY_USER.USER_NM LIKE '%' || #{term} || '%'
AND COMPANY_USER.USE_YN = 'Y' AND COMPANY_USER.DEL_YN = 'N' ) X
WHERE pageindex BETWEEN #{posStart} AND #{count} * #{page}

SELECT X.* FROM ( SELECT COMPANY_USER.USER_NM AS text , COMPANY_USER.USER_CD AS id , ROW_NUMBER() OVER(ORDER BY DISTRIBUTION_PERSON_YN DESC, USER_NM) AS pageindex , CASE DISTRIBUTION_PERSON_YN WHEN N'Y' THEN 1 ELSE 0 END AS selected FROM DOCS_USER COMPANY_USER WHERE 1=1
AND COMPANY_USER.COMPANY_CD = #{companyCd}
AND COMPANY_USER.USE_YN = 'Y' AND COMPANY_USER.DEL_YN = 'N' ) X

/* 로그인한 사용자의 팀장 및 팀장의 대결자 조회 */
SELECT 'teamLeaderList' AS comboCd
	 , DOC_USER.USER_NM || '[' || USER_ID || ']' AS comboLabel
	 , DOC_USER.USER_CD AS comboVal
FROM DOCS_USER DOC_USER
WHERE DOC_USER.USER_CD = (
	SELECT TEAM_LEADER_USER_CD
	FROM DOCS_DEPT
	WHERE DEPT_CD = #{sessionUser.deptCd}
)

/* 로그인한 사용자의 팀장 및 팀장의 대결자 조회 */
SELECT 'teamLeaderList' AS comboCd
	 , DOC_USER.USER_NM AS comboLabel
	 , DOC_USER.USER_ID AS comboVal
FROM DOCS_USER DOC_USER
WHERE DOC_USER.USER_CD = (
	SELECT TEAM_LEADER_USER_CD
	FROM DOCS_DEPT
	WHERE DEPT_CD = #{sessionUser.deptCd}
)

SELECT 'deptList' AS comboCd , docsDept.DEPT_CD AS comboVal , docsDept.DEPT_NM AS comboLabel FROM DOCS_DEPT docsDept JOIN DOCS_USER docsUser ON docsDept.DEPT_CD = docsUser.DEPT_CD WHERE docsUser.BUSINESS_AREA_CD = #{businessAreaCd}
AND docsDept.DEPT_TYPE = '직'
AND docsDept.USE_YN = 'Y' AND docsDept.DEL_YN = 'N' GROUP BY docsDept.DEPT_CD, docsDept.DEPT_NM ORDER BY docsDept.DEPT_CD

/* 생산기술자료 요청 시 사용자 목록 */ SELECT X.* FROM ( SELECT 'userList' AS comboCd , docsUser.USER_CD AS id , docsUser.USER_NM || '[' || docsUser.USER_ID || ']' AS text , docsUser.USER_NM || '[' || docsUser.USER_ID || ']' AS title , ROW_NUMBER() OVER(ORDER BY docsUser.USER_NM, docsUser.USER_ID) AS pageindex FROM DOCS_USER docsUser INNER JOIN DOCS_DEPT docsDept ON docsDept.DEPT_CD = docsUser.DEPT_CD WHERE 1=1
AND BUSINESS_AREA_CD = #{businessAreaCd}
AND USER_NM LIKE '%' || #{term} || '%'
AND docsDept.USE_YN = 'Y' AND docsDept.DEL_YN = 'N' AND docsUser.USE_YN = 'Y' AND docsUser.DEL_YN = 'N' ) X WHERE PAGEINDEX BETWEEN 0 AND 50

SELECT X.* , ROW_NUMBER() OVER(ORDER BY text) AS pageindex FROM ( SELECT USER_CD AS id , USER_NM || '[' || USER_ID || ']' AS text , USER_NM || '[' || USER_ID || ']' AS title , ROW_NUMBER() OVER(ORDER BY USER_NM) AS pageindex FROM DOCS_USER WHERE DEPT_CD = #{deptCd}
AND USER_NM LIKE '%' || #{term} || '%'
AND USE_YN = 'Y' AND DEL_YN = 'N' ) X
WHERE PAGEINDEX BETWEEN #{posStart} AND #{count} * #{page}

/* 부서목록 */ SELECT X.* FROM ( SELECT DEPT_CD AS id , DEPT_NM AS text , DEPT_NM || '[' || DEPT_SHORT_PATH || ']' AS title , ROW_NUMBER() OVER(ORDER BY DEPT_NM) AS pageindex FROM DOCS_DEPT WHERE DEL_YN = 'N' AND USE_YN = 'Y'
AND DEPT_NM LIKE '%' || #{term} || '%'
) X
WHERE PAGEINDEX BETWEEN #{posStart} AND #{count} * #{page}

/* 생산기술자료 배포 받을 수 있는 사용자 목록 (직) combo */ SELECT X.* FROM ( SELECT USER_CD AS id , USER_NM || '[' || DEPT_NM || ']' AS text , USER_NM || '[' || DEPT_NM || ']' AS title FROM DOCS_USER dUser INNER JOIN DOCS_DEPT dDept ON dDept.DEPT_CD = dUser.DEPT_CD WHERE DEPT_TYPE = '직'
AND USER_NM LIKE '%' || #{term} || '%'
AND dUser.USE_YN = 'Y' AND dUser.DEL_YN = 'N' ORDER BY USER_NM ) X LIMIT 10

/* 생산기술자료 배포 받을 수 있는 사용자 목록 (직) combo */ SELECT X.* FROM ( SELECT DEPT_CD AS id , DEPT_NM AS text , DEPT_NM AS title FROM DOCS_DEPT WHERE 1=1
AND DEPT_NM LIKE '%' || #{term} || '%'
AND USE_YN = 'Y' AND DEL_YN = 'N' ORDER BY DEPT_NM ) X LIMIT 10

SELECT COUNT(*)

	FROM DOCS_DRAWING_MEMBER


	FROM DOCS_DOCUMENT_MEMBER


	FROM DOCS_SW_MEMBER

WHERE OBJECT_ID = #{objectId}
AND ACCESS_UID=#{sessionUser.userId}

SELECT X.* FROM ( SELECT USER_ID AS id , USER_NM || '[' || USER_ID || ']' AS text , USER_NM || '[' || USER_ID || ']' AS title , ROW_NUMBER() OVER(ORDER BY USER_NM) AS pageindex FROM DOCS_USER WHERE AUTH_SITE='E' AND USE_YN = 'Y' AND DEL_YN = 'N'
AND USER_NM LIKE '%' || #{term} || '%'
) X
WHERE PAGEINDEX BETWEEN #{posStart} AND #{count} * #{page}

SELECT X.* FROM ( SELECT USER_ID AS id , USER_NM || '[' || USER_ID || ']' AS text , USER_NM || '[' || USER_ID || ']' AS title , ROW_NUMBER() OVER(ORDER BY USER_NM) AS pageindex FROM DOCS_USER WHERE AUTH_SITE='I' AND USE_YN = 'Y' AND DEL_YN = 'N'
AND USER_NM LIKE '%' || #{term} || '%'
) X
WHERE PAGEINDEX BETWEEN #{posStart} AND #{count} * #{page}

SELECT X.* FROM ( SELECT USER_CD AS id , USER_NM || '[' || USER_ID || ']' AS text , USER_NM || '[' || USER_ID || ']' AS title , ROW_NUMBER() OVER(ORDER BY USER_NM) AS pageindex FROM DOCS_USER WHERE AUTH_SITE='I' AND USE_YN = 'Y' AND DEL_YN = 'N'
AND USER_NM LIKE '%' || #{term} || '%'
) X
WHERE PAGEINDEX BETWEEN #{posStart} AND #{count} * #{page}

/* 직위목록 */
SELECT X.*
FROM (
SELECT POSITION_CD AS id
, POSITION_NM AS text
, POSITION_NM AS title
, ROW_NUMBER() OVER(ORDER BY POSITION_NM) AS pageindex
FROM DOCS_POSITION
WHERE DEL_YN = 'N'
AND USE_YN = 'Y'



) X

	WHERE PAGEINDEX BETWEEN #{posStart}
	AND #{count} * #{page}

/* 권한목록 */
SELECT X.*
FROM (
SELECT GROUP_CODE AS id
, GROUP_NM AS text
, GROUP_NM  AS title
, ROW_NUMBER() OVER(ORDER BY GROUP_NM) AS pageindex
FROM DOCS_ROLE_GROUP
WHERE USE_YN = 'Y'



) X

	WHERE PAGEINDEX BETWEEN #{posStart}
	AND #{count} * #{page}

/* 배포권한목록 */
SELECT X.*
FROM (
SELECT DISTRIBUTION_AUTH_CD AS id
, DISTRIBUTION_AUTH_NM AS text
, DISTRIBUTION_AUTH_NM  AS title
, ROW_NUMBER() OVER(ORDER BY DISTRIBUTION_AUTH_NM) AS pageindex
FROM DOCS_DISTRIBUTION_AUTH
WHERE USE_YN = 'Y'



) X

	WHERE PAGEINDEX BETWEEN #{posStart}
	AND #{count} * #{page}
